package p1358

import "testing"

func Test_numberOfSubstrings(t *testing.T) {
	type args struct {
		s string
	}
	tests := []struct {
		name string
		args args
		want int
	}{
		{"Example 1", args{s: "abcabc"}, 10},
		{"Example 2", args{s: "aaacb"}, 3},
		{"Example 3", args{s: "abc"}, 1},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			if got := numberOfSubstrings(tt.args.s); got != tt.want {
				t.Errorf("numberOfSubstrings() = %v, want %v", got, tt.want)
			}
		})
	}
}

func bench(b *testing.B, f func(string) int) {
	b.ReportAllocs()
	for i := 0; i < b.N; i++ {
		f("")
	}
}

func Benchmark_numberOfSubstrings(b *testing.B) {
	bench(b, numberOfSubstrings)
}

func Benchmark_numberOfSubstrings0(b *testing.B) {
	bench(b, numberOfSubstrings0)
}
